import React from 'react';
import { Link } from 'react-router-dom';

function Navbar({ user, onLogout }) {
  const linkStyle = { fontSize: '13px', fontWeight: '500', color: '#333', textDecoration: 'none', marginRight: '30px' };

  return (
    <nav style={{ display: 'flex', justifyContent: 'center', alignItems: 'center', padding: '15px 30px', backgroundColor: '#fff', borderBottom: '1px solid #eee', gap: '40px' }}>
      {/* Left Menu */}
      <div style={{ display: 'flex', gap: '30px' }}>
        <Link to="/" style={linkStyle}>WOMEN</Link>
        <Link to="/" style={linkStyle}>MEN</Link>
        <Link to="/" style={linkStyle}>HANDBAGS</Link>
        <Link to="/" style={linkStyle}>HOME</Link>
        <Link to="/" style={linkStyle}>COLLECTIONS</Link>
      </div>

      {/* Center - Logo */}
      <Link to="/" style={{ display: 'flex', alignItems: 'center', margin: '0 40px' }}>
        <img src="/TheRawLogo.svg" alt="Clothing Shop" style={{ height: '40px', width: 'auto' }} />
      </Link>

      {/* Right Menu */}
      <div style={{ display: 'flex', alignItems: 'center', gap: '30px' }}>
        <span style={linkStyle}>🔍 Search</span>
        <Link to="/" style={linkStyle}>STORES</Link>
        <Link to="/" style={linkStyle}>SAVED</Link>
        {user ? (
          <>
            <Link to="/profile" style={linkStyle}>👤</Link>
            <Link to="/orders" style={linkStyle}>ORDERS</Link>
            <button onClick={onLogout} style={{ padding: '8px 16px', cursor: 'pointer', background: '#ff6b6b', color: 'white', border: 'none', borderRadius: '4px', fontSize: '12px' }}>LOGOUT</button>
          </>
        ) : (
          <>
            <Link to="/login" style={linkStyle}>LOGIN</Link>
            <Link to="/cart" style={linkStyle}>🛒 BAG</Link>
          </>
        )}
      </div>
    </nav>
  );
}

export default Navbar;
